// Filter: only allow messages from sale_users.json IDs
const fs = require('fs');
let saleUsers = [];
try {
  const raw = fs.readFileSync('/home/node/.n8n/data/sale_users.json', 'utf8');
  saleUsers = JSON.parse(raw).map(u => Number(u.telegram_id || u.id));
} catch (e) {
  // Fallback: env var SALE_USER_IDS="123,456"
  saleUsers = (process.env.SALE_USER_IDS || '').split(',').map(s => Number(s.trim())).filter(Boolean);
}
const msg = $input.first().json;
const fromId = Number(msg?.message?.from?.id || msg?.from?.id);
if (!saleUsers.includes(fromId)) {
  return [];
}
return [{ json: {
  chat_id: msg?.message?.chat?.id,
  from_id: fromId,
  username: msg?.message?.from?.username || '',
  text: msg?.message?.text || ''
}}];

