// Parse Claude JSON output, attach to payload
const raw = $input.first().json;
let text = raw.completion || raw.content?.[0]?.text || raw.text || '';
text = text.trim().replace(/^```json\s*/i, '').replace(/```\s*$/i, '');
let parsed;
try { parsed = JSON.parse(text); } catch (e) { parsed = { intent: 'unknown', params: {} }; }
const prev = $('Filter: Sale Users Only').first().json;
return [{ json: { ...prev, intent: parsed.intent, params: parsed.params || {} } }];

const data = $input.first().json;
let reply = '💰 *PHIẾU GIÁ*\n';
if (data.unit) {
  reply += `Căn: ${data.unit.code || data.unit.id}\n`;
  reply += `Diện tích: ${data.unit.area || '-'} m²\n`;
  reply += `Giá niêm yết: ${(data.price_list || 0).toLocaleString('vi-VN')} VNĐ\n`;
  reply += `Sau CK: ${(data.price_final || 0).toLocaleString('vi-VN')} VNĐ\n`;
  reply += `Tình trạng: ${data.unit.status || '-'}\n`;
} else if (Array.isArray(data)) {
  reply += data.slice(0,10).map(u => `• ${u.code} — ${(u.price_final||0).toLocaleString('vi-VN')} VNĐ — ${u.status}`).join('\n');
} else {
  reply += 'Không tìm thấy căn phù hợp.';
}
return [{ json: { reply } }];

const data = $input.first().json;
const leads = Array.isArray(data) ? data : (data.leads || (data.lead ? [data.lead] : []));
let reply = '👤 *THÔNG TIN LEAD*\n';
if (!leads.length) {
  reply += 'Không tìm thấy lead.';
} else {
  reply += leads.slice(0,5).map(l => `• ${l.name} — ${l.phone || '-'} — ${l.source || '-'}\n  Trạng thái: ${l.status || '-'} — Sale: ${l.assigned_sale || 'chưa gán'}`).join('\n\n');
}
return [{ json: { reply } }];

const data = $input.first().json;
const items = Array.isArray(data) ? data : (data.bookings || []);
let reply = '📅 *LỊCH HẸN*\n';
if (!items.length) {
  reply += 'Không có lịch hẹn.';
} else {
  reply += items.slice(0,10).map(b => `• ${b.start_time || b.time} — ${b.client_name || '-'} — ${b.unit_code || ''} ${b.note ? '— '+b.note : ''}`).join('\n');
}
return [{ json: { reply } }];
